import socket
import json
import threading

class GameServer:
    def __init__(self, host='0.0.0.0', port=12345):
        self.host = host
        self.port = port
        self.players = []
        self.game_state = "waiting"
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.server_socket.bind((self.host, self.port))

    def add_player(self, player_name):
        self.players.append(player_name)

    def set_game_state(self, state):
        self.game_state = state

    def handle_request(self, data, addr):
        if data.decode('utf-8') == "status":
            response = {
                "players": self.players,
                "game_state": self.game_state
            }
            response_data = json.dumps(response).encode('utf-8')
            self.server_socket.sendto(response_data, addr)

    def start(self):
        print(f"Game server started on {self.host}:{self.port}")
        while True:
            data, addr = self.server_socket.recvfrom(4096)
            threading.Thread(target=self.handle_request, args=(data, addr)).start()

if __name__ == "__main__":
    server = GameServer()
    server.add_player("Player1")
    server.add_player("Player2")
    server.set_game_state("running")
    server.start()